BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name WHERE {
  ?pkg vocab:NamedElement_name "Alignment and Phasing System" .
  ?pkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type vocab:block .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  ?pkg vocab:NamedElement_name "APS" .
  ?pkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?client ?clientName ?supplier ?supplierName WHERE {
  ?dep rdf:type vocab:dependency .
  ?dep vocab:Dependency_client ?client .
  ?dep vocab:Dependency_supplier ?supplier .
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
  FILTER(
    CONTAINS(LCASE(STR(?clientName)), LCASE("APS")) || 
    CONTAINS(LCASE(STR(?supplierName)), LCASE("APS"))
  )
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?port ?portName ?provided ?required WHERE {
  ?apsBlock vocab:NamedElement_name "APS Operational Blackbox Specification JPL" .
  ?apsBlock vocab:Element_ownedElement+ ?port .
  ?port rdf:type vocab:port .
  OPTIONAL { ?port vocab:NamedElement_name ?portName }
  OPTIONAL { ?port vocab:Port_provided ?provided }
  OPTIONAL { ?port vocab:Port_required ?required }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL> vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  FILTER(?type IN (vocab:port, vocab:proxy%20port, vocab:full%20port))
}
LIMIT 50
